"use client"

import * as React from "react"
import Link from "next/link"
import { Menu, X } from "lucide-react"

const LINKS = ["Collections", "Bespoke", "Maison", "Journal"]

/**
 * Noir header — a hairline utility bar over a serif wordmark and quiet nav.
 */
export function HeaderNoir() {
  const [open, setOpen] = React.useState(false)

  return (
    <header className="border-b border-border bg-background text-foreground">
      <div className="flex items-center justify-center border-b border-border px-5 py-2 text-center font-mono text-[10px] tracking-[0.3em] uppercase text-muted-foreground">
        Complimentary engraving · Worldwide delivery
      </div>

      <div className="mx-auto flex max-w-6xl items-center justify-between px-5 py-5 sm:px-8">
        <nav className="hidden items-center gap-8 md:flex md:flex-1">
          {LINKS.slice(0, 2).map((l) => (
            <Link key={l} href="#" className="text-sm tracking-wide text-muted-foreground transition-colors hover:text-foreground">
              {l}
            </Link>
          ))}
        </nav>

        <Link href="#" className="font-serif text-2xl tracking-[0.2em] uppercase md:flex-1 md:text-center">
          Aurum
        </Link>

        <div className="flex items-center justify-end gap-8 md:flex-1">
          <nav className="hidden items-center gap-8 md:flex">
            {LINKS.slice(2).map((l) => (
              <Link key={l} href="#" className="text-sm tracking-wide text-muted-foreground transition-colors hover:text-foreground">
                {l}
              </Link>
            ))}
          </nav>
          <Link href="#" className="hidden border-b border-primary pb-0.5 text-sm tracking-wide text-primary sm:block">
            Enquire
          </Link>
          <button
            onClick={() => setOpen((o) => !o)}
            aria-label="Menu"
            className="text-foreground md:hidden"
          >
            {open ? <X className="size-5" /> : <Menu className="size-5" />}
          </button>
        </div>
      </div>

      {open && (
        <nav className="grid gap-1 border-t border-border px-5 py-4 md:hidden">
          {LINKS.map((l) => (
            <Link key={l} href="#" className="py-2 text-sm tracking-wide text-muted-foreground hover:text-foreground">
              {l}
            </Link>
          ))}
        </nav>
      )}
    </header>
  )
}

const ROWS = [
  {
    kicker: "I",
    title: "Drawn before it is made",
    body: "Every commission begins as a pencil study, refined with you across as many sittings as it takes. Nothing is cast until the drawing is right.",
  },
  {
    kicker: "II",
    title: "Set under the loupe",
    body: "Stones are placed by a single master setter, by hand, by eye. The work is slow on purpose — that is where the light comes from.",
  },
  {
    kicker: "III",
    title: "Yours, and only yours",
    body: "Each piece is numbered, recorded in the house ledger, and accompanied by a signed certificate of origin. A quiet kind of permanence.",
  },
]

/**
 * Noir features — numbered serif rows divided by gold hairlines.
 */
export function FeatureNoir() {
  return (
    <section className="bg-background px-5 py-20 text-foreground sm:px-8 sm:py-28">
      <div className="mx-auto max-w-4xl">
        <p className="font-mono text-[11px] tracking-[0.35em] uppercase text-primary">The craft</p>

        <div className="mt-10 divide-y divide-border border-y border-border">
          {ROWS.map((r) => (
            <div key={r.kicker} className="grid gap-6 py-10 sm:grid-cols-[auto_1fr] sm:gap-12">
              <span className="font-serif text-3xl text-primary">{r.kicker}</span>
              <div>
                <h3 className="font-serif text-2xl tracking-tight">{r.title}</h3>
                <p className="mt-3 max-w-xl leading-relaxed text-muted-foreground">{r.body}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}

"use client"

import { useRef } from "react"
import { motion, useScroll, useTransform } from "framer-motion"

/**
 * Noir parallax — a serif statement band whose gold glow drifts on scroll.
 */
export function ParallaxNoir() {
  const ref = useRef<HTMLDivElement>(null)
  const { scrollYProgress } = useScroll({ target: ref, offset: ["start end", "end start"] })

  const y = useTransform(scrollYProgress, [0, 1], ["-18%", "18%"])
  const glow = useTransform(scrollYProgress, [0, 1], ["20%", "80%"])
  const opacity = useTransform(scrollYProgress, [0, 0.5, 1], [0.3, 0.7, 0.3])

  return (
    <section
      ref={ref}
      className="relative grid min-h-[460px] place-items-center overflow-hidden border-y border-border bg-background px-5 py-24 text-foreground"
    >
      <motion.div
        aria-hidden
        style={{ top: glow, opacity }}
        className="pointer-events-none absolute left-1/2 size-[60vw] max-w-[700px] -translate-x-1/2 rounded-full bg-[radial-gradient(circle,rgba(200,164,90,0.18),transparent_65%)]"
      />
      <motion.div style={{ y }} className="relative max-w-3xl text-center">
        <p className="font-mono text-[11px] tracking-[0.35em] uppercase text-primary">Maison Aurum</p>
        <p className="mt-6 font-serif text-[clamp(2rem,6vw,4.5rem)] leading-[1.05] tracking-tight text-balance">
          We do not follow the season. We outlast it.
        </p>
      </motion.div>
    </section>
  )
}

import { Check } from "lucide-react"

const TIERS = [
  {
    name: "Atelier",
    price: "Complimentary",
    blurb: "For every piece that leaves the house.",
    points: ["Lifetime cleaning", "Engraving & resizing", "Annual condition report"],
    featured: false,
  },
  {
    name: "Cercle",
    price: "$1,200 / yr",
    blurb: "For the collector who returns.",
    points: ["Everything in Atelier", "Private viewings", "First sight of new work", "Restoration priority"],
    featured: true,
  },
  {
    name: "Patron",
    price: "By invitation",
    blurb: "For the few we know by name.",
    points: ["Everything in Cercle", "Dedicated maître", "Bespoke commissions", "House events"],
    featured: false,
  },
]

/**
 * Noir membership tiers — hairline cards with a gold-framed featured plan.
 */
export function PricingNoir() {
  return (
    <section className="bg-background px-5 py-20 text-foreground sm:px-8 sm:py-28">
      <div className="mx-auto max-w-6xl">
        <div className="max-w-xl">
          <p className="font-mono text-[11px] tracking-[0.35em] uppercase text-primary">Membership</p>
          <h2 className="mt-5 font-serif text-[clamp(2rem,5vw,3.5rem)] leading-[1.02] tracking-tight">
            The circle around the house
          </h2>
        </div>

        <div className="mt-12 grid gap-px border border-border bg-border md:grid-cols-3">
          {TIERS.map((t) => (
            <div
              key={t.name}
              className={`flex flex-col p-8 ${t.featured ? "bg-card ring-1 ring-inset ring-primary" : "bg-card"}`}
            >
              <div className="flex items-center justify-between">
                <p className="font-serif text-2xl tracking-tight">{t.name}</p>
                {t.featured && (
                  <span className="font-mono text-[9px] tracking-[0.25em] uppercase text-primary">Most chosen</span>
                )}
              </div>
              <p className="mt-2 text-sm text-muted-foreground">{t.blurb}</p>
              <p className="mt-6 font-serif text-2xl tracking-tight text-primary">{t.price}</p>

              <ul className="mt-7 flex-1 space-y-3">
                {t.points.map((p) => (
                  <li key={p} className="flex items-start gap-3 text-sm text-muted-foreground">
                    <Check className="mt-0.5 size-4 shrink-0 text-primary" />
                    {p}
                  </li>
                ))}
              </ul>

              <button
                className={`mt-8 py-3 text-sm tracking-[0.15em] uppercase transition-opacity ${
                  t.featured
                    ? "bg-primary text-primary-foreground hover:opacity-90"
                    : "border border-border text-foreground hover:border-primary"
                }`}
              >
                {t.name === "Patron" ? "Enquire" : "Join"}
              </button>
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}
